async function main(): Promise<void> {
  console.log('🌱 Starting seed...');

  // ─── Admin ───────────────────────────────────────────────────
  const adminHash = await bcrypt.hash('Admin@1234', 10);
  const admin = await prisma.user.upsert({
    where: { nationalId: '0000000001' },
    update: {},
    create: {
      nationalId: '0000000001',
      firstName: 'مدیر',
      lastName: 'سیستم',
      phoneNumber: '09120000001',
      judicialDomain: 'مرکزی',
      expertiseField: 'مدیریت',
      role: Role.ADMIN,
      isActive: true,
      passwordHash: adminHash,
    },
  });
  console.log(`✅ Admin: ${admin.firstName} ${admin.lastName}`);

  // ─── Trainees ────────────────────────────────────────────────
  let created = 0, skipped = 0;
  for (const t of TRAINEES) {
    try {
      const user = await prisma.user.upsert({
        where: { nationalId: t.nationalId },
        update: {},
        create: {
          ...t,
          gender: t.gender ?? null,
          role: Role.USER,
          isActive: true,
        },
      });
      await prisma.conversation.upsert({
        where: { userId: user.id },
        update: {},
        create: { userId: user.id },
      });
      created++;
    } catch (e: any) {
      console.warn(`⚠️  Skipped ${t.nationalId}: ${e.message}`);
      skipped++;
    }
  }
  console.log(`✅ Trainees: ${created} created, ${skipped} skipped`);

  // ─── Newsletter ──────────────────────────────────────────────
  const postCount = await prisma.newsletterPost.count();
  if (postCount === 0) {
    await prisma.newsletterPost.createMany({
      data: [
        {
          authorId: admin.id,
          type: 'TEXT',
          body: 'به سامانه کارآموزیار خوش آمدید.\n\nاین سامانه جهت ارتباط کارآموزان عزیز با مرکز طراحی شده است.',
          isPinned: true,
        },
      ],
    });
    console.log('✅ Newsletter post created');
  }

  console.log('\n🎉 Seed completed!');
  console.log('ADMIN → nationalId: 0000000001 | password: Admin@1234');
}

main()
  .catch((e) => { console.error('❌ Seed failed:', e); process.exit(1); })
  .finally(() => prisma.$disconnect());
